css:
/* setting a transparent background for the Heading control */
.fd-form h1 > span,
.fd-form h4 > span,
.fd-form .fd-heading{
   background-color: transparent !important;;
}

/* setting the image as the background of the form */
.fd-form  {
    box-sizing: border-box;
    background: url(https://plumsail.com/assets/forms/templates/cake-order-form-image-01.jpg) no-repeat center center fixed;
    background-size: auto;
    background-size: cover;
}

.fd-form .form-widget > .fd-form {
    background: none;
}

/* setting the background of Grid container */
.fd-form .fd-blur-background{
    backdrop-filter: blur(8px);
    background-color: rgba(255, 255, 255, 0.7);
}

/* adding line to h4 */
.fd-form h4:before, .fd-form h4:after{
    content: '';
    flex: 1 1;
    border-bottom: 1px solid;
    margin: auto;
}

.fd-form h4 {
    margin-right: 10px;
    margin-left: 10px;
}
